export function ThemeProvider({ children }) {
  const [mounted, setMounted] = useState(false);

  // Wait until after client-side hydration
  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  return <NextThemesProvider>{children}</NextThemesProvider>;
}

